import { Component } from "react";
import Slider from "react-slick";
import Descripcion from './Descripcion'

import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

const styles = {
    height: '100%',
}

class MiSlider extends Component {
    render(){
        const settings = {
            dots: true,
            infinite: true,
            speed: 500,
            slidesToShow: 1,
            slidesToScroll: 1,
            autoplay: true,
            autoplaySpeed: 8000,
            vertical: true,
        };

        return(
            <Slider className="slider"{...settings}>
                <div style={styles}>
                    <Descripcion>Hola mundo</Descripcion>
                </div>
                <div style={styles}>
                    <h3>Slide 2</h3>
                </div>
                <div style={styles}>
                    <h3>Slide 3</h3>
                </div>
            </Slider>
        )
    }
}

export default MiSlider
